import pygame
import random
import sys
import base64
import io
import math

pygame.init()

# --- 스프라이트 데이터 ---
SHIP_B64 = ""
FLAME_B64 = ""
PARRY_B64 = ""
METEOR_B64 = ""

ENEMY_SHIP_B64 = ""
# --- 기존 Base64 데이터 및 추가된 폭발 데이터 ---
ENEMY_ATTACK_B64 = ""

EXPLOSION_B64 = ""
ENEMY_ATTACK_SOUND_B64= ""
METEOR_SOUND_B64 = ""
FARRY_SOUND_B64 = ""
EXPLOSION_SOUND_B64 = ""

def load_sprites(b64_data, frames_count, orig_w, orig_h, target_w, target_h, cols=None):
    sheet_bytes = base64.b64decode(b64_data)
    sheet = pygame.image.load(io.BytesIO(sheet_bytes)).convert_alpha()
    
    if cols is None:
        cols = frames_count
        
    frames = []
    for i in range(frames_count):
        row, col = divmod(i, cols)
        rect = pygame.Rect(col * orig_w, row * orig_h, orig_w, orig_h)
        frame = sheet.subsurface(rect)
        scaled_frame = pygame.transform.scale(frame, (target_w, target_h))
        frames.append(scaled_frame)
    return frames

# --- 기본 설정 ---
WIDTH, HEIGHT = 800, 600
FPS = 60
PLAYER_W, PLAYER_H = 50, 50 
PIXEL_SCALE = PLAYER_W / 8  
PARRY_SIZE = int(16 * PIXEL_SCALE) 
ENEMY_W, ENEMY_H = 30, 30

E_SHIP_W, E_SHIP_H = 40, 40
PARRY_RADIUS = (math.hypot(PLAYER_W, PLAYER_H) / 2) * 1.4

# --- 운석 랜더링 계산 ---
ORIG_METEOR_W, ORIG_METEOR_H = 38, 32
RATIO_W, RATIO_H = ORIG_METEOR_W / 96, ORIG_METEOR_H / 96
OFFSET_RATIO_X, OFFSET_RATIO_Y = 29 / 96, 33 / 96
METEOR_RENDER_W = int(ENEMY_W / RATIO_W)
METEOR_RENDER_H = int(ENEMY_H / RATIO_H)
METEOR_DRAW_OFFSET_X = int(METEOR_RENDER_W * OFFSET_RATIO_X)
METEOR_DRAW_OFFSET_Y = int(METEOR_RENDER_H * OFFSET_RATIO_Y)

WHITE  = (255, 255, 255)
GRAY   = (40,  40,  40)
RED    = (220, 50,  50)
YELLOW = (240, 200, 0)
GREEN  = (100, 255, 100)
CYAN   = (0, 255, 255)
MAGENTA= (255, 0, 255)

screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("Parryer")
clock = pygame.time.Clock()

def get_korean_font(size):
    candidates = ["malgungothic", "applegothic", "nanumgothic", "notosanscjk"]
    for name in candidates:
        font = pygame.font.SysFont(name, size)
        if font.get_ascent() > 0: return font
    return pygame.font.SysFont(None, size)

font = get_korean_font(36)
font_big = get_korean_font(72)

# 이미지 초기화
PLAYER_IMAGES = load_sprites(SHIP_B64, 3, 8, 8, PLAYER_W, PLAYER_H)
FLAME_IMAGES  = load_sprites(FLAME_B64, 4, 8, 8, PLAYER_W, PLAYER_H)
PARRY_IMAGES  = load_sprites(PARRY_B64, 4, 16, 16, PARRY_SIZE, PARRY_SIZE)
METEOR_IMAGES = load_sprites(METEOR_B64, 8, 96, 96, METEOR_RENDER_W, METEOR_RENDER_H, cols=8)
ENEMY_SHIP_IMAGES = load_sprites(ENEMY_SHIP_B64, 3, 8, 8, E_SHIP_W, E_SHIP_H, cols=3)

# 파괴 이펙트 초기화 (8x8 -> 40x40으로 확대)
EXPLOSION_IMAGES = load_sprites(EXPLOSION_B64, 6, 8, 8, 40, 40, cols=3)
ORANGE_EXP = EXPLOSION_IMAGES[0:3]
BLUE_EXP = EXPLOSION_IMAGES[3:6]

ATTACK_W, ATTACK_H = 20, 20
attack_bytes = base64.b64decode(ENEMY_ATTACK_B64)
attack_img_raw = pygame.image.load(io.BytesIO(attack_bytes)).convert_alpha()
ATTACK_IMG = pygame.transform.scale(attack_img_raw, (ATTACK_W, ATTACK_H))

enemy_attack_sound_bytes = base64.b64decode(ENEMY_ATTACK_SOUND_B64)
ENEMY_ATTACK_SOUND = pygame.mixer.Sound(io.BytesIO(enemy_attack_sound_bytes))

meteor_sound_bytes = base64.b64decode(METEOR_SOUND_B64)
METEOR_SOUND = pygame.mixer.Sound(io.BytesIO(meteor_sound_bytes))
METEOR_SOUND.set_volume(0.3)

parry_sound_bytes = base64.b64decode(FARRY_SOUND_B64)
PARRY_SOUND = pygame.mixer.Sound(io.BytesIO(parry_sound_bytes))

explosion_sound_bytes = base64.b64decode(EXPLOSION_SOUND_B64)
EXPLOSION_SOUND = pygame.mixer.Sound(io.BytesIO(explosion_sound_bytes))
EXPLOSION_SOUND.set_volume(0.5)

PARRY_SEQ = [3, 3, 3, 3, 2, 2, 2, 1, 1, 0]

LEVELS = [
    {"min_speed": 3, "max_speed": 5,  "spawn": 40, "label": "Stage: 1"},
]

# --- 파괴 애니메이션(폭발) 클래스 ---
class Explosion:
    def __init__(self, center, frames):
        self.frames = frames
        self.frame_idx = 0
        self.timer = 0
        # 0.05초 = 60FPS 기준 3프레임
        self.delay = int(0.05 * FPS) 
        self.image = self.frames[0]
        self.rect = self.image.get_rect(center=center)
        self.active = True

    def update(self):
        self.timer += 1
        if self.timer >= self.delay:
            self.timer = 0
            self.frame_idx += 1
            if self.frame_idx < len(self.frames):
                self.image = self.frames[self.frame_idx]
            else:
                self.active = False

    def draw(self, surface):
        if self.active:
            surface.blit(self.image, self.rect)


# --- 운석 클래스 ---
class Meteor:
    def __init__(self, x, y, w, h, speed):
        self.rect = pygame.Rect(x, y, w, h)
        self.speed = speed
        self.active = True # True면 충돌/피해 판정 적용
        self.frame = 0     # 0: 일반 상태, 1~7: 파괴 모션
        self.anim_timer = 0
        self.frame_delay = int(0.05 * FPS) # 0.05초

    def destroy(self):
        self.active = False
        self.frame = 1 # 파괴 모션 프레임 시작

    def update(self):
        if self.active:
            self.rect.y += self.speed
        else:
            # 파괴 중일 때는 애니메이션 재생
            self.anim_timer += 1
            if self.anim_timer >= self.frame_delay:
                self.anim_timer = 0
                self.frame += 1

    def draw(self, surface):
        draw_pos = (self.rect.x - METEOR_DRAW_OFFSET_X, self.rect.y - METEOR_DRAW_OFFSET_Y)
        if self.frame < 8:
            surface.blit(METEOR_IMAGES[self.frame], draw_pos)


# --- 적 우주선 클래스 ---
class EnemyShip:
    def __init__(self, target_x, target_y):
        self.w = E_SHIP_W
        self.h = E_SHIP_H
        self.x = (WIDTH / 2) - (self.w / 2)
        self.y = -self.h
        self.target_x = target_x
        self.target_y = target_y
        self.speed = 4
        self.rect = pygame.Rect(int(self.x), int(self.y), self.w, self.h)
        self.frame = 1
        
        self.is_in_position = False
        self.attack_timer = random.randint(3 * FPS, 5 * FPS)

    def update(self):
        dx = self.target_x - self.x
        dy = self.target_y - self.y
        dist = math.hypot(dx, dy)

        if dist > self.speed:
            self.x += (dx / dist) * self.speed
            self.y += (dy / dist) * self.speed
        else:
            self.x = self.target_x
            self.y = self.target_y
            self.is_in_position = True

        self.rect.x = int(self.x)
        self.rect.y = int(self.y)

        if self.x < self.target_x - 1:
            self.frame = 2 
        elif self.x > self.target_x + 1:
            self.frame = 0
        else:
            self.frame = 1

    def ready_to_attack(self):
        if self.is_in_position:
            if self.attack_timer > 0:
                self.attack_timer -= 1
                return False
            else:
                self.attack_timer = random.randint(3 * FPS, 5 * FPS)
                return True
        return False

    def draw(self, surface):
        surface.blit(ENEMY_SHIP_IMAGES[self.frame], self.rect)


# --- 적 투사체 클래스 ---
class EnemyAttack:
    def __init__(self, ship):
        self.ship = ship
        self.w = ATTACK_W
        self.h = ATTACK_H
        
        self.x = ship.rect.centerx - self.w // 2
        self.y = ship.rect.bottom
        self.rect = pygame.Rect(int(self.x), int(self.y), self.w, self.h)
        
        self.charge_timer = 1 * FPS 
        self.dx = 0
        self.dy = 0
        self.speed = 6
        self.active = True
        self.reflected = False 

    def update(self, current_player_rect):
        if self.charge_timer > 0:
            self.charge_timer -= 1
            if self.ship in enemy_ships:
                self.x = self.ship.rect.centerx - self.w // 2
                self.y = self.ship.rect.bottom
            self.rect.topleft = (int(self.x), int(self.y))
            
            if self.charge_timer == 0:
                px, py = current_player_rect.center
                angle = math.atan2(py - self.rect.centery, px - self.rect.centerx)
                self.dx = math.cos(angle) * self.speed
                self.dy = math.sin(angle) * self.speed
                ENEMY_ATTACK_SOUND.play()
        else:
            self.x += self.dx
            self.y += self.dy
            self.rect.topleft = (int(self.x), int(self.y))
            
            if self.y > HEIGHT + 50 or self.y < -50 or self.x < -50 or self.x > WIDTH + 50:
                self.active = False
    
    def draw(self, surface):
        surface.blit(ATTACK_IMG, self.rect)


def draw_hud(score, level_cfg, lives, parry_cooldown):
    # 좌상단: 스코어, 스테이지
    score_text = font.render(f"Score: {score}", True, WHITE)
    stage_text = font.render(f"{level_cfg['label']}", True, YELLOW)
    screen.blit(score_text, (10, 10))
    screen.blit(stage_text, (10, 50))

    # 우상단: 체력, 패링 쿨타임
    lives_text = font.render(f"Lives: {'♥ ' * lives}", True, RED)
    screen.blit(lives_text, lives_text.get_rect(right=WIDTH - 10, top=10))

    cd_sec = (parry_cooldown + FPS - 1) // FPS
    if cd_sec == 0:
        cd_text = font.render("Parry: Ready (F)", True, GREEN)
    else:
        cd_text = font.render(f"Parry: {cd_sec}s", True, WHITE)
    screen.blit(cd_text, cd_text.get_rect(right=WIDTH - 10, top=50))

def game_over_screen(score):
    screen.fill(GRAY)
    screen.blit(font_big.render("GAME OVER", True, RED), (220, 220))
    screen.blit(font.render(f"Score: {score}", True, WHITE), (350, 310))
    screen.blit(font.render("R: Restart   Q: Quit", True, WHITE), (270, 360))
    pygame.display.flip()
    while True:
        for e in pygame.event.get():
            if e.type == pygame.QUIT: pygame.quit(); sys.exit()
            if e.type == pygame.KEYDOWN:
                if e.key == pygame.K_r: return True
                if e.key == pygame.K_q: pygame.quit(); sys.exit()



def main():
    global enemy_ships
    
    player_rect = pygame.Rect(WIDTH // 2 - PLAYER_W // 2, HEIGHT - 100, PLAYER_W, PLAYER_H)
    meteors = []
    enemy_ships = []
    enemy_attacks = []
    explosions = [] 
    
    score = 0
    lives = 3
    invincible = 0
    
    stage_timer = 0
    ships_spawned = 0
    meteor_spawn_timer = 0
    
    parry_cooldown = 0
    parry_anim_idx = -1 
    parry_anim_timer = 0
    parry_active_timer = 0 
    
    show_hitbox = False

    while True:
        clock.tick(FPS)
        screen.fill(GRAY)
        
        for e in pygame.event.get():
            if e.type == pygame.QUIT: pygame.quit(); sys.exit()
            if e.type == pygame.KEYDOWN:
                if e.key == pygame.K_d:
                    show_hitbox = not show_hitbox
                if e.key == pygame.K_f and parry_cooldown <= 0:
                    parry_cooldown = 8 * FPS
                    parry_active_timer = int(0.4 * FPS)
                    parry_anim_idx = 0
                    parry_anim_timer = 0
                    PARRY_SOUND.play()

        stage_timer += 1
        
        if parry_cooldown > 0: parry_cooldown -= 1
        if parry_active_timer > 0: parry_active_timer -= 1
            
        if parry_anim_idx >= 0:
            parry_anim_timer += 1
            if parry_anim_timer >= 3:
                parry_anim_idx += 1
                parry_anim_timer = 0
                if parry_anim_idx >= len(PARRY_SEQ):
                    parry_anim_idx = -1

        keys = pygame.key.get_pressed()

        current_image = PLAYER_IMAGES[1]
        flame_offset_x = 0

        if keys[pygame.K_LEFT] and player_rect.left > 0:
            player_rect.x -= 5
            current_image = PLAYER_IMAGES[0]
            flame_offset_x = -PIXEL_SCALE
        elif keys[pygame.K_RIGHT] and player_rect.right < WIDTH:
            player_rect.x += 5
            current_image = PLAYER_IMAGES[2]
            flame_offset_x = PIXEL_SCALE
        
        if keys[pygame.K_UP] and player_rect.top > 0: player_rect.y -= 5
        if keys[pygame.K_DOWN] and player_rect.bottom < HEIGHT: player_rect.y += 5

        level_cfg = LEVELS[0]

        # --- 적 우주선 생성 로직 ---
        if stage_timer >= 5 * FPS and ships_spawned < 8:
            if (stage_timer - 5 * FPS) % int(0.5 * FPS) == 0:
                target_x = (WIDTH / 9) * (ships_spawned + 1) - (E_SHIP_W / 2)
                target_y = 80
                enemy_ships.append(EnemyShip(target_x, target_y))
                ships_spawned += 1

        # --- 운석 생성 로직 ---
        meteor_spawn_timer += 1
        if meteor_spawn_timer >= level_cfg["spawn"]:
            meteor_spawn_timer = 0
            x = random.randint(0, WIDTH - ENEMY_W)
            speed = random.randint(level_cfg["min_speed"], level_cfg["max_speed"])
            meteors.append(Meteor(x, -ENEMY_H, ENEMY_W, ENEMY_H, speed))

        # --- 위치 및 애니메이션 업데이트 ---
        for ship in enemy_ships:
            ship.update()
            if ship.ready_to_attack():
                enemy_attacks.append(EnemyAttack(ship))

        for atk in enemy_attacks:
            atk.update(player_rect)
        enemy_attacks = [atk for atk in enemy_attacks if atk.active]
        
        for exp in explosions:
            exp.update()
        explosions = [exp for exp in explosions if exp.active]

        survived_meteors = []
        for m in meteors:
            m.update()
            if m.active:
                if m.rect.top < HEIGHT:
                    survived_meteors.append(m)
                else:
                    score += 1
            else:
                if m.frame < 8:
                    survived_meteors.append(m)
        meteors = survived_meteors

        # --- 반사된 투사체 충돌 판정 ---
        for atk in enemy_attacks:
            if atk.active and atk.reflected:
                for ship in enemy_ships[:]:
                    if atk.rect.colliderect(ship.rect):
                        explosions.append(Explosion(ship.rect.center, ORANGE_EXP))
                        enemy_ships.remove(ship)
                        score += 50
                        EXPLOSION_SOUND.play()
                for m in meteors:
                    if m.active and atk.rect.colliderect(m.rect):
                        m.destroy()
                        score += 10
                        METEOR_SOUND.play()

        # --- 플레이어 피격 판정 ---
        if invincible > 0:
            invincible -= 1
        else:
            hit = False
            
            for atk in enemy_attacks:
                if atk.active and not atk.reflected and player_rect.colliderect(atk.rect):
                    if parry_active_timer > 0:
                        atk.reflected = True
                        if atk.charge_timer > 0:
                            atk.dx = 0
                            atk.dy = -atk.speed
                            atk.charge_timer = 0
                        else:
                            atk.dx *= -1
                            atk.dy *= -1
                        
                        # 패링 성공 시 처리: 쿨다운 초기화, 무적 프레임 및 모션 즉시 종료
                        parry_cooldown = 0 
                        parry_active_timer = 0 
                        parry_anim_idx = -1
                    else:
                        hit = True
                        atk.active = False
                        break

            if not hit:
                for m in meteors:
                    if m.active and player_rect.colliderect(m.rect):
                        if parry_active_timer > 0:
                            pass 
                        else:
                            hit = True
                            m.destroy()
                            METEOR_SOUND.play()
                            break
            
            if not hit:
                for ship in enemy_ships:
                    if player_rect.colliderect(ship.rect):
                        if parry_active_timer > 0:
                            pass 
                        else:
                            hit = True
                            break

            if hit:
                lives -= 1
                invincible = 90
                if lives <= 0:
                    if game_over_screen(score): main()
                    return

        # --- 그리기 작업 ---
        blink = (invincible // 10) % 2 != 0

        if not blink:
            screen.blit(current_image, player_rect)
            flame_frame_idx = (pygame.time.get_ticks() // 100) % 4
            flame_x = player_rect.x + flame_offset_x
            flame_y = player_rect.bottom - PIXEL_SCALE
            screen.blit(FLAME_IMAGES[flame_frame_idx], (flame_x, flame_y))
            
            if parry_anim_idx >= 0:
                frame_number = PARRY_SEQ[parry_anim_idx]
                parry_img = PARRY_IMAGES[frame_number]
                parry_rect = parry_img.get_rect(center=player_rect.center)
                screen.blit(parry_img, parry_rect)

        for ship in enemy_ships:
            ship.draw(screen)

        for atk in enemy_attacks:
            atk.draw(screen)

        for m in meteors:
            m.draw(screen)
            
        for exp in explosions:
            exp.draw(screen)

        if show_hitbox:
            pygame.draw.rect(screen, GREEN, player_rect, 2)
            pygame.draw.circle(screen, CYAN, player_rect.center, int(PARRY_RADIUS), 2)
            for m in meteors:
                if m.active: pygame.draw.rect(screen, RED, m.rect, 2)
            for ship in enemy_ships:
                pygame.draw.rect(screen, YELLOW, ship.rect, 2)
            for atk in enemy_attacks:
                color = CYAN if atk.reflected else MAGENTA
                pygame.draw.rect(screen, color, atk.rect, 2)

        draw_hud(score, level_cfg, lives, parry_cooldown)
        pygame.display.flip()
        
if __name__ == "__main__":
    main()